const TELEGRAM_MAX_LENGTH = 3900;
const truncateMessage = (value, max = TELEGRAM_MAX_LENGTH) => {
  const text = String(value || '').trim();
  if (text.length <= max) {
    return text;
  }
  return `${text.slice(0, Math.max(max - 35, 0)).trimEnd()}\n\n...alerta cortado para caber no Telegram.`;
};

const row = items[0]?.json ?? {};
const currentOk = Number(row.current_ok ?? 0);
const avgOk = Number(row.avg_ok ?? 0);
const currentFailed = Number(row.current_failed ?? 0);
const avgFailed = Number(row.avg_failed ?? 0);

const alerts = [];
if (avgOk >= 5 && currentOk < avgOk * 0.4) {
  alerts.push(`queda anormal de pagamentos: janela atual=${currentOk}, baseline=${avgOk.toFixed(2)}`);
}
if (currentFailed >= 3 && currentFailed > Math.max(avgFailed * 2, 3)) {
  alerts.push(`alta anormal de webhooks com falha: janela atual=${currentFailed}, baseline=${avgFailed.toFixed(2)}`);
}

if (alerts.length === 0) {
  const store = typeof $getWorkflowStaticData === 'function' ? $getWorkflowStaticData('global') : null;
  if (store) {
    delete store.lastAlertSignature;
    delete store.lastAlertSentAt;
  }
  return [];
}

const signature = JSON.stringify(alerts);
const now = Date.now();
const cooldownMs = 60 * 60 * 1000;
const store = typeof $getWorkflowStaticData === 'function' ? $getWorkflowStaticData('global') : null;

if (store) {
  const lastSignature = String(store.lastAlertSignature ?? '');
  const lastSentAt = Number(store.lastAlertSentAt ?? 0);
  const withinCooldown = lastSignature === signature && lastSentAt > 0 && now - lastSentAt < cooldownMs;

  if (withinCooldown) {
    return [];
  }

  store.lastAlertSignature = signature;
  store.lastAlertSentAt = now;
}

const message = truncateMessage([
  'Alerta FeConect: comportamento anormal detectado',
  '',
  ...alerts.map((line) => `- ${line}`),
  '',
  `metricas: pagamentos_ok_hora=${currentOk} (baseline ${avgOk.toFixed(2)}), webhooks_falhos_hora=${currentFailed} (baseline ${avgFailed.toFixed(2)})`,
].join('\n'));

return [{
  json: {
    hasAlerts: true,
    alerts,
    message,
    metrics: row,
  },
}];
